SELECT cp.*, b.bill_no as billNo, c.`name` as customerName, p.project_name as projectName FROM `elder_customer_payment` cp LEFT JOIN elder_bill b ON cp.bill_id = b.id LEFT JOIN elder_customer c on c.id = cp.customer_id LEFT JOIN elder_project p on p.id = cp.project_id WHERE cp.del_flag = 0
AND cp.project_id IN (
#{id}
)
AND cp.project_id = #{data.projectId}
AND c.`name` LIKE concat(concat('%',#{data.customerName}),'%')
AND cp.checkin_id LIKE concat(concat('%',#{data.checkinId}),'%')
AND b.bill_no LIKE concat(concat('%',#{data.billNo}),'%')
AND cp.customer_id = #{data.customerId}
AND cp.payment_method_code = #{data.paymentMethodCode}
AND cp.transaction_type_code = #{data.transactionTypeCode}
AND cp.confirm_flag = #{data.confirmFlag}
ORDER BY cp.create_time DESC

SELECT
cp.*,
b.bill_no as billNo,
c.`name` as customerName,
p.project_name as projectName
FROM
`elder_customer_payment` cp
LEFT JOIN elder_bill b ON cp.bill_id = b.id
LEFT JOIN elder_customer c on c.id = cp.customer_id
LEFT JOIN elder_project p on p.id = cp.project_id
WHERE
cp.del_flag = 0

    AND  cp.project_id IN (

        #{id}

    )


    AND cp.project_id = #{data.projectId}


    AND c.`name` LIKE concat(concat('%',#{data.customerName}),'%')


    AND cp.checkin_id LIKE concat(concat('%',#{data.checkinId}),'%')


    AND b.bill_no LIKE concat(concat('%',#{data.billNo}),'%')


    AND cp.customer_id = #{data.customerId}


    AND cp.payment_method_code = #{data.paymentMethodCode}


    AND cp.transaction_type_code = #{data.transactionTypeCode}


    AND cp.confirm_flag = #{data.confirmFlag}


    AND  cp.id IN (

        #{id}

    )

ORDER BY cp.create_time DESC
